INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 2, 24001, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 102301, 401, 10046, 0.0, "2020/07/31 12:00:00", "アヤネ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 1, 24002, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 102301, 402, 10046, 2.21, "2020/07/31 12:00:00", "アヤネ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 2, 24003, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 102301, 403, 10046, 0.0, "2020/07/31 12:00:00", "アヤネ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 1, 2, 24004, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 192201, 701, 10046, 1.99, "2020/07/31 12:00:00", "アサヒ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 1, 24005, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 192201, 702, 10046, 2.21, "2020/07/31 12:00:00", "アサヒ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 1, 2, 24006, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 192201, 703, 10046, 3.33, "2020/07/31 12:00:00", "アサヒ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 2, 24007, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 192301, 801, 10046, 0.0, "2020/07/31 12:00:00", "部員３", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 1, 24008, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 192301, 802, 10046, 2.68, "2020/07/31 12:00:00", "部員３", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 2, 24009, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 192301, 803, 10046, 0.0, "2020/07/31 12:00:00", "部員３", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 1, 1, 24010, "やった！", 192501, 501, 10046, 0.0, "2020/07/31 12:00:00", "", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 1, 1, 24011, "勝ったよ！", 192501, 502, 10046, 0.0, "2020/07/31 12:00:00", "", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 1, 1, 24012, "いい調子！", 192501, 503, 10046, 0.0, "2020/07/31 12:00:00", "", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 6, 24013, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 113501, 111, 10046, 5.33, "2020/07/31 12:00:00", "ミサト", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 1, 24014, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 113501, 112, 10046, 6.85, "2020/07/31 12:00:00", "ミサト", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 1, 24015, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 113501, 113, 10046, 3.0, "2020/07/31 12:00:00", "ミサト", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 1, 24016, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 192401, 611, 10046, 6.11, "2020/07/31 12:00:00", "ダイチ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 1, 24017, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 192401, 612, 10046, 6.75, "2020/07/31 12:00:00", "ダイチ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 2, 24018, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 192401, 613, 10046, 0.0, "2020/07/31 12:00:00", "ダイチ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 1, 2, 24019, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 113401, 211, 10046, 4.52, "2020/07/31 12:00:00", "ハツネ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 1, 2, 24020, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 113401, 212, 10046, 3.89, "2020/07/31 12:00:00", "ハツネ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 1, 24021, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 113401, 213, 10046, 13.49, "2020/07/31 12:00:00", "ハツネ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 1, 24022, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 106501, 311, 10046, 3.17, "2020/07/31 12:00:00", "カヤ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 1, 24023, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 106501, 312, 10046, 4.42, "2020/07/31 12:00:00", "カヤ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 1, 6, 24024, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 106501, 313, 10046, 2.89, "2020/07/31 12:00:00", "カヤ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 3, 4, 24025, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 102301, 421, 10046, 3.71, "2020/07/31 12:00:00", "アヤネ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 1, 2, 24026, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 192201, 721, 10046, 5.1, "2020/07/31 12:00:00", "アサヒ", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 3, 1, 24027, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 192301, 821, 10046, 4.34, "2020/07/31 12:00:00", "部員３", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 1, 1, 24028, "いい勝負だったよ\nまたやろうね", 192501, 521, 10046, 0.0, "2020/07/31 12:00:00", "", 0.0, 0.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 1, 24029, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 113501, 101, 10046, 5.62, "2020/07/31 12:00:00", "ミサト", 0.0, -360.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 1, 24030, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 113501, 102, 10046, 9.58, "2020/07/31 12:00:00", "ミサト", 0.0, -360.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 2, 24031, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 113501, 103, 10046, 0.0, "2020/07/31 12:00:00", "ミサト", 0.0, -360.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 1, 2, 24032, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 113501, 104, 10046, 9.13, "2020/07/31 12:00:00", "ミサト", 0.0, -360.0);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2030/12/17 14:59:59", 24, 2, 1, 24033, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 113501, 105, 10046, 8.27, "2020/07/31 12:00:00", "ミサト", 0.0, -360.0);
